function validateAndConvertU256Input(value: any, errorMsg: string): string[] {
    if (typeof value !== "number" && typeof value !== "bigint") {
        throw new StarknetPluginError(errorMsg);
    }

    value = BigInt(value);

    const lo = value & U128_MAX;
    const hi = value >> BigInt(128);

    return [toNumericString(lo), toNumericString(hi)];
}

function joinStaticCalls (dataArray) {
    const trimmed = dataArray.map(trim0x);
    const cumulativeSum = (sum => value => { sum += value; return sum; })(0);
    return {
        offsets: trimmed
            .map(d => d.length / 2)
            .map(cumulativeSum)
            .reduce((acc, val, i) => acc | BigInt(val) << BigInt(32 * i), 0n),
        data: '0x' + trimmed.join(''),
    };
}

#getSimilarStrings(
  stringToCompare: string,
  otherStrings: Iterable<string>,
  maxEditDistance: number = EDIT_DISTANCE_THRESHOLD,
): string[] {
  return [...otherStrings]
    .map((s) => [s, editDistance(s, stringToCompare)] as const)
    .sort(([_, d1], [__, d2]) => d1 - d2)
    .filter(([_, d]) => d <= maxEditDistance)
    .map(([s]) => s);
}

export function encodePriceSqrt(reserve1: BigNumberish, reserve0: BigNumberish): BigNumber {
  return BigNumber.from(
    new bn(reserve1.toString())
      .div(reserve0.toString())
      .sqrt()
      .multipliedBy(new bn(2).pow(96))
      .integerValue(3)
      .toString()
  )
}

cairoPathBindings(binds: { [x: string]: string }, dockerArgs: string[]) {
    const { cairoPaths } = this;
    if (cairoPaths.length) {
        const cairoPathsEnv: string[] = [];
        cairoPaths.forEach((path, i) => {
            const cPath = `/src/cairo-paths-${i}`;
            binds[path] = cPath;
            cairoPathsEnv.push(cPath);
        });

        dockerArgs.push("--env");
        dockerArgs.push(`CAIRO_PATH=${cairoPathsEnv.join(":")}`);
    }
}

function getGasPriceUrlForChain(options: GasReporterOptions): string {
  if (options.gasPriceApi) return options.gasPriceApi;

  const apiKey = (options.etherscan) ? `${DEFAULT_API_KEY_ARGS}${options.etherscan}` : "";

  if (options.L2) {
    if (!L2[options.L2]) throw new Error;
    return `${L2[options.L2!].baseUrl}${DEFAULT_GAS_PRICE_API_ARGS}${apiKey}`;
  }

  if (!L1[options.L1!]) throw new Error();
  return `${L1[options.L1!].baseUrl}${DEFAULT_GAS_PRICE_API_ARGS}${apiKey}`;
}

function getBlockUrlForChain(options: GasReporterOptions): string {
  if (!options.L2) return "";
  if (options.getBlockApi) return options.getBlockApi;

  const apiKey = (options.etherscan) ? `${DEFAULT_API_KEY_ARGS}${options.etherscan}` : "";

  if (!L1[options.L1!]) throw new Error();

  return `${L1[options.L1!].baseUrl}${DEFAULT_GET_BLOCK_API_ARGS}${apiKey}`;
}

function getBlobBaseFeeUrlForChain(options: GasReporterOptions): string {
  if (!options.L2) return "";
  if (options.blobBaseFeeApi) return options.blobBaseFeeApi;

  const apiKey = (options.etherscan) ? `${DEFAULT_API_KEY_ARGS}${options.etherscan}` : "";

  return `${L2[options.L2!].baseUrl}${DEFAULT_BLOB_BASE_FEE_API_ARGS}${L2[options.L2!].gasPriceOracle}${apiKey}`;
}

function getBaseFeePerByteUrlForChain(options: GasReporterOptions): string {
  if (options.L2 !== "arbitrum") return "";

  const apiKey = (options.etherscan) ? `${DEFAULT_API_KEY_ARGS}${options.etherscan}` : "";

  return `${L2[options.L2!].baseUrl}${DEFAULT_BASE_FEE_PER_BYTE_API_ARGS}${apiKey}`;
}

function getCalldataBytesGas(data: string): number {
  let total = 0;
  // String hex-prefixed, 1 byte = 2 hex chars
  for (let i = 2; i < data.length; i++) {
    if (i % 2 === 0) {
      total = (data[i] === "0" && data[i + 1] === "0")
        ? total + 4
        : total + 16;
    }
  }
  return total;
}

