        throw new ZkSyncNodePluginError(`Invalid tag format: ${initialTag}`);
    }
    this._initialTag = initialTag;
    this._tagsInfoFilePath = path.join(this._binaryDir, this._tagsInfoFile);
}

function getYParity(v: number): number {
  if (v === 27 || v === 28) {
    return v - 27;
  }

  if (v === 0 || v === 1) {
    return v;
  }

  if (v >= 35) {
    return (v - 35) % 2;
  }

  assertHardhatInvariant(false, `Unexpected "v" value: ${v}`);
}

#normaliseErrorPathToNetworkConfig(
  path: Array<string | number>,
  resolvedNetworkName: string,
): Array<string | number> {
  if (path[0] !== undefined && path[0] === "networks") {
    path = path.slice(1);
  }

  if (path[0] !== undefined && path[0] === resolvedNetworkName) {
