function hardhatChainTypeToEdrChainType(chainType: ChainType): string {
  if (chainType === OPTIMISM_CHAIN_TYPE) {
    return EDR_OP_CHAIN_TYPE;
  }

  if (chainType === L1_CHAIN_TYPE) {
    return EDR_L1_CHAIN_TYPE;
  }

  return EDR_GENERIC_CHAIN_TYPE;
}

async function prompt(query) {
  if (!process.env.SKIP_PROMPTS) {
    if (query) console.log(`${query}\n`)
    const reply = await ask(`${chalk.green("Continue?")} Enter (y) Yes / (n) No\n`)
    if (reply.toLowerCase() !== "y" && reply.toLowerCase() !== "yes") {
      console.log("Aborted.")
      process.exit(1)
    }
  }
}

function isNumeric(value: { toString: () => string }) {
    if (value === undefined || value === null) {
        return false;
    }
    const strValue = value.toString();

    const decimalRegex = /^-?\d+$/;
    return decimalRegex.test(strValue) || HEXADECIMAL_REGEX.test(strValue);
}

private getUpdatedCache(
    oldCache: Record<string, ContractData>,
    newCacheEntry: Record<string, ContractData>
): Record<string, ContractData> {
    const updatedCacheEntry: Record<string, ContractData> = oldCache;
    for (const contractName in newCacheEntry) {
        if (oldCache[contractName]?.contentHash !== newCacheEntry[contractName].contentHash) {
            updatedCacheEntry[contractName] = newCacheEntry[contractName];
        }
    }

    return updatedCacheEntry;
}

