function adaptPath(root: string, newPath: string): string {
    let adaptedPath = newPath;
    if (newPath[0] === "~") {
        adaptedPath = path.normalize(path.join(process.env.HOME, newPath.slice(1)));
    } else if (!path.isAbsolute(newPath)) {
        adaptedPath = path.normalize(path.join(root, newPath));
    }
    return adaptedPath;
}

function renderWithGasDelta(val: string, delta: number, withColor?: boolean) {
  if (delta === 0) return val;

  let deltaString = commify(delta);
  if (withColor) {
    deltaString = delta > 0 ? chalk.redBright(`+${deltaString}`) : chalk.green(`${deltaString}`);
  } else {
    deltaString = delta > 0 ? `+${deltaString}` : `${deltaString}`;
  }
  return `${val} ${deltaString}`;
}

export function rayPow(a: BigNumberValue, p: BigNumberValue): BigNumber {
  let x = valueToZDBigNumber(a);
  let n = valueToZDBigNumber(p);
  let z = !n.modulo(2).eq(0) ? x : valueToZDBigNumber(RAY);

  for (n = n.div(2); !n.eq(0); n = n.div(2)) {
    x = rayMul(x, x);

    if (!n.modulo(2).eq(0)) {
      z = rayMul(z, x);
    }
  }
  return z;
}

