setProposal(actions, description) {
  if (Array.isArray(actions)) {
    this.targets = actions.map(a => a.target);
    this.values = actions.map(a => a.value || 0n);
    this.data = actions.map(a => a.data || '0x');
  } else {
    ({ targets: this.targets, values: this.values, data: this.data } = actions);
  }
  this.description = description;
  return this;
}

function calculateHarmonicAvgLiq(period: number, secondsPerLiqCumulatives: [BigNumberish, BigNumberish]) {
  const [secondsPerLiq0, secondsPerLiq1] = secondsPerLiqCumulatives.map(BigNumber.from)
  const delta = secondsPerLiq1.sub(secondsPerLiq0)

  const maxUint160 = BigNumber.from(2).pow(160).sub(1)
  return maxUint160.mul(period).div(delta.shl(32))
}

const parseGitignore = (gitignorePath: string): string[] => {
	if (!existsSync(gitignorePath)) {
		return [];
	}

	const content = readFileSync(gitignorePath, 'utf-8');
	return content
		.split('\n')
		.map((line: string) => line.trim())
		.filter((line: string) => line && !line.startsWith('#'));
};

function blankSummary() {
  const empty = () => ({
    total: 0,
    covered: 0,
    skipped: 0,
    pct: "Unknown",
  });

  return {
    lines: empty(),
    statements: empty(),
    functions: empty(),
    branches: empty(),
    branchesTrue: empty(),
  };
}

addHits = (aHits, bHits) => {
  if (typeof aHits === "number" && typeof bHits === "number") {
    return aHits + bHits;
  } else if (Array.isArray(aHits) && Array.isArray(bHits)) {
    return aHits.map((a, i) => (a || 0) + (bHits[i] || 0));
  }
  return null;
}

function normalizeWatermarks(specified = {}) {
  Object.entries(watermarks.getDefault()).forEach(([k, value]) => {
    const specValue = specified[k];
    if (!Array.isArray(specValue) || specValue.length !== 2) {
      specified[k] = value;
    }
  });

  return specified;
}

writeFile(file) {
  if (file === null || file === "-") {
    return new ConsoleWriter();
  }
  if (path.isAbsolute(file)) {
    throw new Error(`Cannot write to absolute path: ${file}`);
  }
  file = path.resolve(this.baseDir, file);
  fs.mkdirSync(path.dirname(file), { recursive: true });
  return new FileContentWriter(fs.openSync(file, "w"));
}

getRelativeName() {
  const parent = this.getParent();
  const myPath = this.path;
  let relPath;
  let i;
  const parentPath = parent ? parent.path : new Path([]);
  if (parentPath.ancestorOf(myPath)) {
    relPath = new Path(myPath.elements());
    for (i = 0; i < parentPath.length; i += 1) {
      relPath.shift();
    }
    return this.asRelative(relPath.toString());
  }
  return this.asRelative(this.path.toString());
}

_createPkg() {
  const dirParents = toDirParents(this._initialList);
  if (dirParents.length === 1) {
    return new ReportTree(dirParents[0]);
  }

  return new ReportTree(
    ReportNode.createRoot(dirParents),
    pkgSummaryPrefix(dirParents, this._commonParent),
  );
}

_createNested() {
  const nodeMap = Object.create(null);
  const topPaths = [];
  this._initialList.forEach((o) => {
    const node = new ReportNode(o.path, o.fileCoverage);
    addAllPaths(topPaths, nodeMap, o.path, node);
  });

  const topNodes = topPaths.map((node) => foldIntoOneDir(node));
  if (topNodes.length === 1) {
    return new ReportTree(topNodes[0]);
  }

  return new ReportTree(ReportNode.createRoot(topNodes));
}

visit(visitor, state) {
  if (this.isSummary()) {
    visitor.onSummary(this, state);
  } else {
    visitor.onDetail(this, state);
  }

  this.getChildren().forEach((child) => {
    child.visit(visitor, state);
  });

  if (this.isSummary()) {
    visitor.onSummaryEnd(this, state);
  }
}

getPath(node) {
  if (typeof node === "string") {
    return node;
  }
  let filePath = node.getQualifiedName();
  if (node.isSummary()) {
    if (filePath !== "") {
      filePath += "/index.html";
    } else {
      filePath = "index.html";
    }
  } else {
    filePath += ".html";
  }
  return filePath;
}

create(name, cfg) {
  cfg = cfg || {};
  let Cons;
  try {
    Cons = require(path.join(__dirname, "lib", name, "index.cjs"));
  } catch (e) {
    if (e.code !== "MODULE_NOT_FOUND") {
      throw e;
    }

    Cons = require(name);
  }

  return new Cons(cfg);
}

